Here are the public test cases for feature3_request_context:
{
  "description": "Request middleware attaches a composed execution context containing caller-provided context values and configured data-source models, then continues the request chain.",
  "cases": [
    {
      "input": {
        "action": "middleware_context",
        "enableMockData": false,
        "extraContext": {
          "tenant": "acme"
        },
        "sources": [
          {
            "context": "Catalog",
            "modelValue": "catalog-model"
          },
          {
            "context": "Inventory",
            "modelValue": "inventory-model"
          }
        ]
      },
      "expected_output": "{\n  \"context\": {\n    \"Catalog\": {\n      \"name\": \"catalog-model\"\n    },\n    \"Inventory\": {\n      \"name\": \"inventory-model\"\n    },\n    \"tenant\": \"acme\"\n  },\n  \"hasFormatError\": true,\n  \"hasSchema\": true,\n  \"nextCalled\": true\n}\n"
    }
  ]
}

